import React from 'react';
import { Link } from 'react-router-dom';

export default function AuthLayout({ children, title, subtitle, footerLink }) {
  return (
    <div className="login-container">
      <img src="/assets/login_hero.png" className="login-bg-image" alt="Background" />

      <div className="login-glass-card animate-slide">
        <div className="login-header">
          <div className="login-logo">
            <img src="/assets/logo.png" alt="KEC" onError={(e) => e.target.style.display='none'} />
            <div style={{ color: 'white', fontWeight: 800 }}>KEC</div>
          </div>
          <h1>KEC BUS PORTAL</h1>
          <p>{subtitle || 'Kongu Engineering College'}</p>
        </div>

        {children}

        {footerLink && (
          <p className="auth-switch">
            {footerLink.text}{' '}
            <Link to={footerLink.to}>{footerLink.label}</Link>
          </p>
        )}

        <div style={{ marginTop: 32, textAlign: 'center', fontSize: 11, color: 'var(--text-muted)' }}>
          © {new Date().getFullYear()} Kongu Engineering College<br/>
          Bus Transportation Department
        </div>
      </div>
    </div>
  );
}
